body:
Found in v4.106. The problem is that assigning a value from cpp to verilog input ports is handled differently with or without `--coverage` option.

Attached is the testcase.zip, which includes two files, top.v and main.cpp.
[testcase.zip](https://github.com/verilator/verilator/files/5760492/testcase.zip)

In top.v, the only difference between `vo0`/`vo1` and `vo0`/`vo1w` is that the location of the `if` condition and their logic should be equivalent. The simulation results of `vo0` and `vo0w` should always be same. Same as `vo1` and `vo1w`.

In main.cpp, it assigns 1 to input `di` if output `dt` is 1; otherwise it assigns 0. This action is done upon the rising clock edge and, yes, it could be a race condition. However, I don't expect `--coverage` option to change the result.

If running verilator without `--coverage` option, the result shows that `vo0` and `vo0w` always change at the same time. This is expected.
  1650: dt=1  di=0  vo0=0  vo0w=0  vo1=0  vo1w=0
  1700: dt=1  di=1  vo0=0  vo0w=0  vo1=0  vo1w=0
  1750: dt=0  di=1  vo0=1  vo0w=1  vo1=0  vo1w=0
  1800: dt=0  di=0  vo0=1  vo0w=1  vo1=0  vo1w=0
  1850: dt=0  di=0  vo0=0  vo0w=0  vo1=0  vo1w=0
  1900: dt=0  di=0  vo0=0  vo0w=0  vo1=0  vo1w=0
  1950: dt=0  di=0  vo0=0  vo0w=0  vo1=0  vo1w=0

But if running verilator with `--coverage` option, then the result is different (and wrong). Now `vo0` and `vo0w` change at different time. Same thing happens to `vo1` and `vo1w` too.
  1650: dt=1  di=0  vo0=0  vo0w=0  vo1=0  vo1w=0
  1700: dt=1  di=1  vo0=0  vo0w=0  vo1=0  vo1w=0
  1750: dt=0  di=1  vo0=1  vo0w=0  vo1=0  vo1w=0
  1800: dt=0  di=0  vo0=1  vo0w=0  vo1=0  vo1w=0
  1850: dt=0  di=0  vo0=0  vo0w=0  vo1=0  vo1w=1
  1900: dt=0  di=0  vo0=0  vo0w=0  vo1=0  vo1w=1
  1950: dt=0  di=0  vo0=0  vo0w=0  vo1=0  vo1w=0


Below is the verilog and cpp code

````verilog
// top.v
module top (
	output		vo0,
	output		vo0w,
	output		vo1,
	output		vo1w,
	output		dt,
	input		di,
	input		clk,
	input		resetn
);

reg [3:0]	dtb;
assign		dt = dtb[1];

always @(posedge clk or negedge resetn)
if (!resetn)
	dtb <= 4'b1;
else
	dtb <= {dtb[2:0], dtb[3]};

reg		vo0b;
assign		vo0 = vo0b;

always @(posedge clk or negedge resetn)
if (!resetn)
	vo0b <= 1'b0;
else if (dtb[1] & di)
	vo0b <= 1'b1;
else
	vo0b <= 1'b0;

reg		vo0wb;
assign		vo0w = vo0wb;
wire		dt0w = dtb[1] & di;

always @(posedge clk or negedge resetn)
if (!resetn)
	vo0wb <= 1'b0;
else if (dt0w)
	vo0wb <= 1'b1;
else
	vo0wb <= 1'b0;

reg		vo1b;
assign		vo1 = vo1b;

always @(posedge clk or negedge resetn)
if (!resetn)
	vo1b <= 1'b0;
else if (dtb[2] & di)
	vo1b <= 1'b1;
else
	vo1b <= 1'b0;

reg		vo1wb;
assign		vo1w = vo1wb;
wire		dt1w = dtb[2] & di;

always @(posedge clk or negedge resetn)
if (!resetn)
	vo1wb <= 1'b0;
else if (dt1w)
	vo1wb <= 1'b1;
else
	vo1wb <= 1'b0;

endmodule
````

````cpp
// main.cpp
#include <verilated.h>
#include "Vtop.h"

#define MAX_TIME_TICK	2000UL

vluint64_t sim_time = 0;

double sc_time_stamp()	// called by $time in verilog
{
	return sim_time;
}

int main(int argc, char **argv, char **env)
{
	Verilated::commandArgs(argc, argv);	// remember args
	Vtop *top = new Vtop;

	top->clk = 0;
	top->resetn = 1;

	while (!Verilated::gotFinish() && sim_time < MAX_TIME_TICK) {
		if (sim_time < 200)
			top->resetn = 1;
		else if (sim_time < 400)
			top->resetn = 0;
		else
			top->resetn = 1;

		if ((sim_time % 100) == 0)
			top->clk = 1;
		else if ((sim_time % 50) == 0)
			top->clk = 0;

		if ((sim_time % 100) == 0) {
			if (top->dt)
				top->di = 1;
			else
				top->di = 0;
		}
		if ((sim_time % 50) == 0)
			VL_PRINTF("%6lu: dt=%0x  di=%0x  vo0=%0x  vo0w=%0x  vo1=%0x  vo1w=%0x\n", sim_time, top->dt, top->di, top->vo0, top->vo0w, top->vo1, top->vo1w);

		top->eval();
		++sim_time;
	}

	top->final();

#if VM_COVERAGE
	VerilatedCov::write("coverage.dat");
#endif
	delete top;
	return 0;
}
````
